class NoteService:
    """Adds and retrieves notes, persisting each through a Store."""

    def __init__(self, store):
        self.store = store
        self._next = 0

    def render(self, title, body):
        return f"{title}: {body}"

    def add(self, title, body):
        note_id = str(self._next)
        self._next += 1
        self.store.put(note_id, self.render(title, body))
        return note_id

    def get(self, note_id):
        return self.store.get(note_id)
